import{_ as a,o,c as i,ag as s}from"./chunks/framework.BZohXCq9.js";const p=JSON.parse('{"title":"INFORMACIÓN GENERAL","description":"","frontmatter":{},"headers":[],"relativePath":"maxstaff/funciones.md","filePath":"maxstaff/funciones.md"}'),n={name:"maxstaff/funciones.md"};function r(t,e,l,d,c,u){return o(),i("div",null,[...e[0]||(e[0]=[s('<h1 id="informacion-general" tabindex="-1">INFORMACIÓN GENERAL <a class="header-anchor" href="#informacion-general" aria-label="Permalink to &quot;INFORMACIÓN GENERAL&quot;">​</a></h1><blockquote><p>MaxStaff transforma la experiencia de moderación mediante un sistema de <strong>&quot;MODO-STAFF&quot;</strong> que optimiza las tareas de monitoreo y sanción todas estas sanciones se manejan mediante menus interactivos, baneos, kicks, muteos, historial, permisos, inventario, etc....</p></blockquote><h2 id="_1-modo-staff" tabindex="-1">1. Modo Staff <a class="header-anchor" href="#_1-modo-staff" aria-label="Permalink to &quot;1. Modo Staff&quot;">​</a></h2><blockquote><p>Cuando ejecutas el comando <code>/staff</code>, el plugin realiza automáticamente las siguientes acciones para facilitar tu trabajo:</p></blockquote><ul><li><code>Guardado de Inventario:</code> Tu inventario actual, armadura, modo de juego y nivel de hambre se guardan de forma segura para restaurarse cuando salgas del modo, si por motivos X te desconectas del servidor, tus datos quedarán guardados en un archivo, así, cuando vuelvas a entrar al servidor recuperarás tus cosas.</li><li><code>Capacidades Administrativas:</code> Se activa el vuelo, obtienes invulnerabilidad, se bloquea la pérdida de hambre, nadie te puede escuchar, no puedes golpear a los jugadores, etc...</li><li><code>Vanish Automático:</code> Al entrar en este modo te vuelves invisible para los jugadores que no tengan permisos especiales, se le puede otorgar un permiso especial a los jugadores para poder ver al staff en vanish <a href="/maxstaff/comandos-permisos.html">Permisos</a></li><li><code>Action Bar:</code> Aparecerá un mensaje constante sobre tu barra de inventario indicando tu estado de invisibilidad.</li></ul><h2 id="_2-inventario" tabindex="-1">2. Inventario <a class="header-anchor" href="#_2-inventario" aria-label="Permalink to &quot;2. Inventario&quot;">​</a></h2><blockquote><p>Al activar el modo staff recibirás un conjunto de herramientas configurables en los siguientes slots:</p></blockquote><ul><li><code>Sanción (Slot 0):</code> Haz clic derecho sobre un jugador o usa la herramienta para abrir el menú rápido de sanciones.</li><li><code>Freeze (Slot 1):</code> Permite congelar instantáneamente a un jugador para realizar una revisión (SS).</li><li><code>Jugadores Online (Slot 4):</code> Abre un menú con las cabezas de todos los jugadores conectados para teletransportarte rápidamente.</li><li><code>Teletransportaación (Slot 6):</code> Un reloj que te permitirá atravesar bloques para moverte más rapido.</li><li><code>Inspeccionar (Slot 7):</code> Haz clic derecho sobre un jugador para ver su inventario y armadura en tiempo real.</li><li><code>Vanish (Slot 8):</code> Activa o desactiva tu invisibilidad rápidamente sin necesidad de escribir comandos.</li></ul><h2 id="_3-invisiblidad" tabindex="-1">3. Invisiblidad <a class="header-anchor" href="#_3-invisiblidad" aria-label="Permalink to &quot;3. Invisiblidad&quot;">​</a></h2><blockquote><p>Oculta tu presencia en el servidor usando el comando <code>/vanish</code>. Los jugadores sin el permiso <code>maxstaff.see.vanish</code> no podrán verte ni en el mundo ni en la lista de jugadores.</p></blockquote><ul><li><strong>Efectos:</strong> Al activarlo o desactivarlo escucharás un sonido de confirmación.</li></ul><h2 id="_4-comando-espia" tabindex="-1">4. Comando espía <a class="header-anchor" href="#_4-comando-espia" aria-label="Permalink to &quot;4. Comando espía&quot;">​</a></h2><blockquote><p>Usando el comando <code>/cmdspy</code> permite a los miembros del staff monitorear en tiempo real los comandos que ejecutan los jugadores.</p></blockquote><ul><li>Los mensajes aparecerán con el formato configurado en <code>messages_es.yml</code><br><em>(ejemplo: <code>[SPY] Usuario: /msg ...</code>)</em>.</li></ul><h2 id="_5-canal-staff" tabindex="-1">5. Canal Staff <a class="header-anchor" href="#_5-canal-staff" aria-label="Permalink to &quot;5. Canal Staff&quot;">​</a></h2><blockquote><p>Usando el comando <code>/sc &lt;mensaje&gt;</code> te abrirá un canal de comunicación exclusivo y seguro para el equipo de staff.</p></blockquote><ul><li>Los mensajes enviados aquí no son visibles para los jugadores normales y están formateados para destacar en el chat.</li></ul><h2 id="_6-inspeccion-silenciosa" tabindex="-1">6. Inspección Silenciosa <a class="header-anchor" href="#_6-inspeccion-silenciosa" aria-label="Permalink to &quot;6. Inspección Silenciosa&quot;">​</a></h2><blockquote><p>Mientras estés en <strong>Modo Staff</strong>, puedes interactuar silenciosamente con contenedores (cofres, ender chests, barriles, etc.):</p></blockquote><ul><li><strong>Cofres de Jugadores:</strong> Puedes abrir cofres sin que se reproduzca la animación ni el sonido de apertura, permitiéndote revisar su contenido sin alertar al sospechoso.</li><li><strong>Control de Inspección:</strong> El plugin evita que dos miembros del staff inspeccionen el mismo contenedor al mismo tiempo para prevenir conflictos de datos.</li></ul>',20)])])}const f=a(n,[["render",r]]);export{p as __pageData,f as default};
